160→function LoggedInShell({children}: {children: React.ReactNode}) {
161→  const {session} = useAuth();
162→  const userId = session?.user.id;
163→  const [toast, setToast] = useState<{message: string; visible: boolean}>({
164→    message: '',
165→    visible: false,
166→  });
167→
168→  const handleNewNotification = useCallback((payload: Record<string, unknown>) => {
169→    const message =
170→      (payload.message as string) || 'You have a new notification';
171→    setToast({message, visible: true});
172→  }, []);
173→
174→  const handleDismissToast = useCallback(() => {
175→    setToast(prev => ({...prev, visible: false}));
176→  }, []);
177→
178→  useRealtimeNotifications(userId, {
179→    onNewNotification: handleNewNotification,
180→  });
181→
182→  return (
183→    <View style={styles.shellContainer}>
184→      {children}
185→      <Toast
186→        message={toast.message}
187→        visible={toast.visible}
188→        onDismiss={handleDismissToast}
189→        type="info"
190→      />
191→    </View>
192→  );
193→}
